#!/usr/bin/env python3
"""Apply the Taiji Native-V2 AutoDL training patch to an existing remote tree."""

from __future__ import annotations

import argparse
import base64
import os
from pathlib import Path

PAYLOADS = {
    'requirements-autodl.txt': '',
    'scripts/data_prep/download_pretrain_mix_v1.py': '',
    'scripts/data_prep/audit_1b_training_assets.py': '',
    'scripts/build_native_vocab_corpus.py': '',
    'scripts/train_native_text_sp.py': '',
    'scripts/verify_native_tokenizer.py': '',
    'scripts/native_v2/pretrain.py': '',
    'scripts/training/autodl_native_v2.sh': '',
    'taiji/tokenizer_native_v2.py': '',
    'taiji/tokenizer_contract.json': '',
    'taiji/__init__.py': '',
}

EXECUTABLES = {
    'scripts/training/autodl_native_v2.sh',
}


def apply_patch(project_dir: Path) -> None:
    written = []
    for rel_path, encoded in PAYLOADS.items():
        target = project_dir / rel_path
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_bytes(base64.b64decode(encoded))
        if rel_path in EXECUTABLES:
            mode = target.stat().st_mode
            target.chmod(mode | 0o111)
        written.append((rel_path, target.stat().st_size))

    print('Patch applied to', project_dir)
    for rel_path, size in written:
        print(f'  - {rel_path} ({size} bytes)')
    print('')
    print('Next commands:')
    print('  cd ' + str(project_dir))
    print('  export HF_ENDPOINT=https://hf-mirror.com')
    print('  pip install -r requirements-autodl.txt')
    print('  export TAIJI_DATA_PRESET=stage0_smoke')
    print('  bash scripts/training/autodl_native_v2.sh data')
    print('  export TAIJI_DATA_PRESET=english_boost_mirror')
    print('  bash scripts/training/autodl_native_v2.sh data')
    print('  bash scripts/training/autodl_native_v2.sh audit')
    print('  bash scripts/training/autodl_native_v2.sh tokenizer')
    print('  bash scripts/training/autodl_native_v2.sh smoke')


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description='Apply Taiji AutoDL training patch')
    parser.add_argument(
        'project_dir',
        nargs='?',
        default='/root/autodl-tmp/taiji',
        help='Existing Taiji project directory on AutoDL',
    )
    return parser.parse_args()


if __name__ == '__main__':
    args = parse_args()
    apply_patch(Path(args.project_dir).resolve())
